import { RiArrowDownSLine, RiArrowUpSLine } from 'react-icons/ri';

export function LoadMoreButton(theme: any, onClick: any, gridVisibility: boolean) {

	function handleArrowIcon() {
		if(!gridVisibility){
			return (
				<button className={`w-screen ${theme.themeBgClassName}`} onClick={onClick}>
					<RiArrowDownSLine />
				</button>
			);
		}

		return (
			<button className={`w-screen ${theme.themeBgClassName}`} onClick={onClick}>
				<RiArrowUpSLine />
			</button>
		);
	}

	return (
		<>
			<button className={`w-screen ${theme.themeBgClassName}`} onClick={onClick}>
				<RiArrowDownSLine />
			</button>
		</>
	);
}
